const LANGFLOW_URL = 'http://localhost:7860/api/v1/run/Master%20Flow';
const JWT_NODE_ID = 'TextInput-ddCdP';

export async function sendMessage(userMessage) {
  const token = localStorage.getItem('jwt_token');

  if (!token) {
    return {
      ok: false,
      error: 'Please log in to continue. No authentication token was found.',
    };
  }

  const response = await fetch(LANGFLOW_URL, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      input_value: userMessage,
      output_type: 'chat',
      input_type: 'chat',
      tweaks: {
        [JWT_NODE_ID]: {
          input_value: token,
        },
      },
    }),
  });

  const data = await response.json().catch(() => null);

  if (!response.ok) {
    throw new Error(data?.message || data?.detail || `API returned ${response.status}: ${response.statusText}`);
  }

  const text = data?.outputs?.[0]?.outputs?.[0]?.results?.message?.text;

  if (!text) {
    throw new Error('No response text returned from Langflow.');
  }

  return {
    ok: true,
    text,
    raw: data,
  };
}

export default {
  sendMessage,
};
